function b64decode(b64: string): Uint8Array {
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr;
}

const FAVICON_ICO = "";

const APPLE_TOUCH_ICON = "";

const ICON_192 = "";

const ICON_512 = "";

const CACHE_HEADERS = { "Cache-Control": "public, max-age=86400" };

export function serveAsset(path: string): Response | null {
  switch (path) {
    case "/favicon.ico":
      return new Response(b64decode(FAVICON_ICO), { headers: { ...CACHE_HEADERS, "Content-Type": "image/x-icon" } });
    case "/apple-touch-icon.png":
      return new Response(b64decode(APPLE_TOUCH_ICON), { headers: { ...CACHE_HEADERS, "Content-Type": "image/png" } });
    case "/icon-192.png":
      return new Response(b64decode(ICON_192), { headers: { ...CACHE_HEADERS, "Content-Type": "image/png" } });
    case "/icon-512.png":
      return new Response(b64decode(ICON_512), { headers: { ...CACHE_HEADERS, "Content-Type": "image/png" } });
    case "/manifest.webmanifest":
      return new Response(
        JSON.stringify({
          name: "shrtnr",
          short_name: "shrtnr",
          icons: [
            { src: "/icon-192.png", sizes: "192x192", type: "image/png" },
            { src: "/icon-512.png", sizes: "512x512", type: "image/png" },
          ],
          start_url: "/",
          display: "standalone",
        }),
        { headers: { ...CACHE_HEADERS, "Content-Type": "application/manifest+json" } },
      );
    case "/robots.txt":
      return new Response("User-agent: *\nAllow: /\n", {
        headers: { ...CACHE_HEADERS, "Content-Type": "text/plain" },
      });
    default:
      return null;
  }
}
